     4	namespace InventoryFlow.Application.Common.Behaviors;
     5	
     6	/// <summary>Runs FluentValidation before MediatR handlers.</summary>
     7	public sealed class ValidationBehavior<TRequest, TResponse>(IEnumerable<IValidator<TRequest>> validators) : IPipelineBehavior<TRequest, TResponse>
     8	    where TRequest : notnull
     9	{
    10	    /// <inheritdoc />
    11	    public async Task<TResponse> Handle(TRequest request, RequestHandlerDelegate<TResponse> next, CancellationToken cancellationToken)
    12	    {
    13	        var context = new ValidationContext<TRequest>(request);
    14	        var failures = (await Task.WhenAll(validators.Select(validator => validator.ValidateAsync(context, cancellationToken))))
    15	            .SelectMany(result => result.Errors).Where(error => error is not null).ToList();
    16	        if (failures.Count != 0) throw new ValidationException(failures);
    17	        return await next(cancellationToken);
    18	    }
    19	}

