     9	/// <summary>Provides workspace-scoped product catalog endpoints.</summary>
    10	[ApiController]
    11	[Authorize]
    12	[Route("api/products")]
    13	public sealed class ProductsController(ISender sender, ICurrentWorkspace currentWorkspace) : ControllerBase
    14	{
    15	    /// <summary>Creates a product in the current workspace.</summary>
    16	    [HttpPost]
    17	    [ProducesResponseType<ProductResponse>(StatusCodes.Status201Created)]
    18	    [ProducesResponseType(StatusCodes.Status403Forbidden)]
    19	    public async Task<ActionResult<ProductResponse>> Create(CreateProductRequest request, CancellationToken cancellationToken)
    20	    {
    21	        var workspace = await currentWorkspace.GetAsync(cancellationToken);
    22	        if (workspace is null) return Forbid();
    23	        var product = await sender.Send(new CreateProductCommand(workspace.Id, request.Name, request.Sku), cancellationToken);
    24	        return Created($"/api/products/{product.Id}", product);
    25	    }
    26	
    27	    /// <summary>Lists active products in the current workspace.</summary>
    28	    [HttpGet]
    29	    [ProducesResponseType<IReadOnlyList<ProductResponse>>(StatusCodes.Status200OK)]
    30	    [ProducesResponseType(StatusCodes.Status403Forbidden)]
    31	    public async Task<ActionResult<IReadOnlyList<ProductResponse>>> List(CancellationToken cancellationToken)
    32	    {
    33	        var workspace = await currentWorkspace.GetAsync(cancellationToken);
    34	        if (workspace is null) return Forbid();
    35	        return Ok(await sender.Send(new ListProductsQuery(workspace.Id), cancellationToken));
    36	    }
    37	
    38	    /// <summary>Idempotently archives a product in the current workspace.</summary>
    39	    [HttpDelete("{id:guid}")]
    40	    [ProducesResponseType(StatusCodes.Status204NoContent)]
    41	    [ProducesResponseType(StatusCodes.Status403Forbidden)]
    42	    [ProducesResponseType(StatusCodes.Status404NotFound)]
    43	    public async Task<IActionResult> Archive(Guid id, CancellationToken cancellationToken)
    44	    {
    45	        var workspace = await currentWorkspace.GetAsync(cancellationToken);
    46	        if (workspace is null) return Forbid();
    47	        return await sender.Send(new ArchiveProductCommand(workspace.Id, id), cancellationToken) ? NoContent() : NotFound();
    48	    }
    49	}

